# Unit Tests for `group_by` Function

```python
import pytest
from typing import Any


def group_by(items: list, key_fn) -> dict:
    """Group items by the result of applying key_fn to each item."""
    result = {}
    for item in items:
        k = key_fn(item)
        result.setdefault(k, []).append(item)
    return result


class TestGroupByHappyPath:
    """Tests for normal, expected usage."""

    def test_group_by_integers_by_parity(self):
        """Group integers by even/odd."""
        items = [1, 2, 3, 4, 5, 6]
        result = group_by(items, lambda x: x % 2)
        assert result == {1: [1, 3, 5], 0: [2, 4, 6]}

    def test_group_by_strings_by_length(self):
        """Group strings by their length."""
        items = ["a", "bb", "ccc", "dd", "e"]
        result = group_by(items, lambda x: len(x))
        assert result == {1: ["a", "e"], 2: ["bb", "dd"], 3: ["ccc"]}

    def test_group_by_dicts_by_field(self):
        """Group dictionaries by a specific field."""
        items = [
            {"name": "Alice", "age": 30},
            {"name": "Bob", "age": 25},
            {"name": "Charlie", "age": 30},
        ]
        result = group_by(items, lambda x: x["age"])
        assert result == {
            30: [{"name": "Alice", "age": 30}, {"name": "Charlie", "age": 30}],
            25: [{"name": "Bob", "age": 25}],
        }

    def test_group_by_objects_by_attribute(self):
        """Group objects by an attribute."""
        class Person:
            def __init__(self, name, department):
                self.name = name
                self.department = department

        items = [
            Person("Alice", "Engineering"),
            Person("Bob", "Sales"),
            Person("Charlie", "Engineering"),
        ]
        result = group_by(items, lambda x: x.department)
        assert len(result) == 2
        assert len(result["Engineering"]) == 2
        assert len(result["Sales"]) == 1
        assert result["Engineering"][0].name == "Alice"

    def test_group_by_preserves_order(self):
        """Items within groups maintain insertion order."""
        items = [1, 2, 3, 4, 5]
        result = group_by(items, lambda x: x % 2)
        assert result[1] == [1, 3, 5]
        assert result[0] == [2, 4]


